// --- types.d.ts ---
// types.d.ts
export interface ForecastItem {
  day: string;
  icon: string;
  high: number;
  low: number;
}

export interface WeatherCardProps {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit?: "C" | "F";
  forecast: ForecastItem[];
}

export interface HookReturn {
  formattedTemperature: string;
  conditionIcon: string;
  formattedHumidity: string;
  formattedWind: string;
  displayUnit: string;
  forecastItems: ForecastItem[];
}

export interface HeaderProps {
  city: string;
}

export interface CurrentWeatherProps {
  temperature: string;
  condition: string;
  icon: string;
}

export interface DetailsProps {
  humidity: string;
  windSpeed: string;
}

export interface ForecastProps {
  items: ForecastItem[];
  unit: string;
}

export interface ForecastItemProps {
  item: ForecastItem;
  unit: string;
}

// --- constants.ts ---
// constants.ts — static data, mappings, configurations
// No React, no design system imports. Pure data only.

export const WEATHER_ICONS: Record<string, string> = {
  SUNNY: '☀️',
  CLOUDY: '☁️',
  RAIN: '🌧️',
  STORM: '⛈️',
  SNOW: '❄️',
  MIST: '🌫️',
  DEFAULT: '❓',
};

export const UNIT_LABELS = {
  C: '°C',
  F: '°F',
} as const;

export const HUMIDITY_SUFFIX = '%';
export const WIND_SPEED_SUFFIX = 'km/h';


// --- hooks.ts ---
// hooks.ts — state, handlers, data transformations
import { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import type { Props, HookReturn } from './types';
import * as constants from './constants';

export function useComponent(props: Props): HookReturn {
  const {
    temperature,
    condition,
    humidity,
    windSpeed,
    unit = 'C',
    forecast,
  } = props;

  const formattedTemperature = useMemo(() => `${Math.round(temperature)}°`, [temperature]);

  const displayUnit = useMemo(() => (unit === 'F' ? '°F' : '°C'), [unit]);

  const formattedHumidity = useMemo(() => `${humidity}%`, [humidity]);

  const formattedWind = useMemo(() => {
    const suffix = unit === 'F' ? 'mph' : 'km/h';
    return `${windSpeed} ${suffix}`;
  }, [windSpeed, unit]);

  const conditionIcon = useMemo(() => {
    const c = condition.toLowerCase();
    if (c.includes('sun')) return '☀️';
    if (c.includes('cloud')) return '☁️';
    if (c.includes('rain')) return '🌧️';
    if (c.includes('storm')) return '⛈️';
    return '🌡️';
  }, [condition]);

  return {
    formattedTemperature,
    conditionIcon,
    formattedHumidity,
    formattedWind,
    displayUnit,
    forecastItems: forecast,
  };
}


// --- components/Header.tsx ---
// components/Header.tsx — reusable sub-component
import React from 'react';
import { Box, Stack, Heading, Text } from '@ggui-ai/design/primitives';
import type { HeaderProps } from './types';

export function Header(props: HeaderProps) {
  const formattedDate = new Intl.DateTimeFormat('en-US', {
    weekday: 'long',
    month: 'short',
    day: 'numeric'
  }).format(new Date());

  return (
    <Box padding="var(--ggui-spacing-4)">
      <Stack gap={1}>
        <Heading level={2} color="var(--ggui-color-onSurface)">
          {props.city}
        </Heading>
        <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
          {formattedDate}
        </Text>
      </Stack>
    </Box>
  );
}


// --- components/CurrentWeather.tsx ---
// components/CurrentWeather.tsx — reusable sub-component
import React from 'react';
import { Stack, Box, Text, Heading } from '@ggui-ai/design/primitives';
import type { CurrentWeatherProps } from './types';

export function CurrentWeather(props: CurrentWeatherProps) {
  const { temperature, condition, icon } = props;

  return (
    <Stack
      align="center"
      justify="center"
      gap={8}
      style={{ padding: 'var(--ggui-spacing-8, 32px)' }}
    >
      <Box>
        <Text size="4xl" as="span">
          <span role="img" aria-label={condition}>
            {icon}
          </span>
        </Text>
      </Box>
      <Heading level={1} color="var(--ggui-color-onSurface, #18181b)">
        {temperature}
      </Heading>
      <Text variant="bodyLarge" color="var(--ggui-color-onSurfaceVariant, #52525b)">
        {condition}
      </Text>
    </Stack>
  );
}


// --- components/Details.tsx ---
// components/Details.tsx — reusable sub-component
import React from 'react';
import { Row, Stack, Text, Icon } from '@ggui-ai/design/primitives';
import type { DetailsProps } from '../types';

export function Details({ humidity, windSpeed }: DetailsProps) {
  return (
    <Row gap="var(--ggui-spacing-6)" justify="around">
      <Stack align="center" gap={1}>
        <Icon name="water_drop" size={24} />
        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
          Humidity
        </Text>
        <Text variant="bodyLarge">{humidity}</Text>
      </Stack>
      <Stack align="center" gap={1}>
        <Icon name="air" size={24} />
        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
          Wind Speed
        </Text>
        <Text variant="bodyLarge">{windSpeed}</Text>
      </Stack>
    </Row>
  );
}


// --- components/Forecast.tsx ---
// components/Forecast.tsx — reusable sub-component
import React from 'react';
import { Stack, Row, Box, Divider, Text } from '@ggui-ai/design/primitives';
import type { ForecastProps } from './types';

export function Forecast(props: ForecastProps) {
  const { items, unit } = props;

  return (
    <Box>
      <Divider margin={16} />
      <Row justify="between">
        {items.map((item, index) => (
          <Stack key={index} align="center" gap={8}>
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
              {item.day}
            </Text>
            <Text size="2xl">
              {item.icon}
            </Text>
            <Stack direction="horizontal" gap={4} align="center">
              <Text variant="bodySmall" weight="semibold" color="var(--ggui-color-onSurface)">
                {item.high}°{unit}
              </Text>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                {item.low}°{unit}
              </Text>
            </Stack>
          </Stack>
        ))}
      </Row>
    </Box>
  );
}


// --- ui.tsx ---
// components/index.tsx — main component composing sub-components
import React from 'react';
import { Card, Stack, Divider } from '@ggui-ai/design/primitives';
import type { WeatherCardProps as Props } from './types';
import { useWeatherCard } from './hook';
import { Header } from './components/Header';
import { CurrentWeather } from './components/CurrentWeather';
import { Details } from './components/Details';
import { Forecast } from './components/Forecast';

export function Component(props: Props) {
  const {
    formattedTemperature,
    conditionIcon,
    formattedHumidity,
    formattedWind,
    displayUnit,
    forecastItems,
  } = useWeatherCard(props);

  return (
    <Card
      padding="var(--ggui-spacing-6, 24px)"
      style={{
        maxWidth: '400px',
        backgroundColor: 'var(--ggui-color-surface, #fafafa)',
        width: '100%',
      }}
    >
      <Stack gap="var(--ggui-spacing-6, 24px)">
        <Header city={props.city} />
        <CurrentWeather temperature={formattedTemperature} condition={props.condition} icon={conditionIcon} />
        <Details humidity={formattedHumidity} windSpeed={formattedWind} />
        <Divider margin={0} />
        <Forecast items={forecastItems} unit={displayUnit} />
      </Stack>
    </Card>
  );
}


// --- entrypoint.tsx ---
// entrypoint.tsx — wires hooks + component, export default
import React from 'react';
import type { Props } from './types';
import { useComponent } from './hooks';
import { Component } from './components/index';

export default function Entrypoint(props: Props) {
  const state = useComponent(props);
  return <Component {...props} {...state} />;
}
